import{_ as i,o as a,c as t,ag as n}from"./chunks/framework.BY_wD62d.js";const g=JSON.parse('{"title":"上下文类型","description":"","frontmatter":{"_rawMarkdown":"# 上下文类型\\n\\n基于对人类认知模式的简化映射与工程化思考，OpenViking 将上下文抽象为 **资源、记忆、能力三种**基本类型，每种类型在 Agent 中有不同的用途。\\n\\n## 概览\\n\\n| 类型 | 用途 | 生命周期 | 主动性 |\\n|------|------|----------|--------|\\n| **Resource** | 知识和规则 | 长期，相对静态 | 用户添加 |\\n| **Memory** | Agent 的认知 | 长期，动态更新 | Agent 记录 |\\n| **Skill** | 可调用的能力 | 长期，静态 | Agent 调用 |\\n\\n## Resource（资源）\\n\\n资源是 Agent 可以引用的外部知识。\\n\\n### 特点\\n\\n- **用户主动**：由用户主动添加的资源类信息，用于补充大模型的知识，比如产品手册、代码仓库\\n- **静态内容**：添加后内容很少发生变化，通常为用户主动修改\\n- **结构化存储**：将按照项目或主题以目录层级组织，并提取出多层信息。\\n\\n### 示例\\n\\n- API 文档、产品手册\\n- FAQ 数据库、代码仓库\\n- 研究论文、技术规范\\n\\n### 使用\\n\\n```python\\n# 添加资源\\nclient.add_resource(\\n    \\"https://docs.example.com/api.pdf\\",\\n    reason=\\"API 文档\\"\\n)\\n\\n# 搜索资源\\nresults = client.find(\\n    \\"认证方法\\",\\n    target_uri=\\"viking://resources/\\"\\n)\\n```\\n\\n## Memory（记忆）\\n\\n记忆分为用户记忆和Agent记忆，是 Agent 关于用户和世界的学习知识。\\n\\n### 特点\\n\\n- **Agent 主动：**由 Agent 主动提取和记录的记忆信息\\n- **动态更新：**由 Agent 从交互中持续更新\\n- **个性化：**针对特定用户或 特定 Agent 学习记录\\n\\n### 8 种分类\\n\\n| 分类 | 位置 | 说明 | 更新策略 |\\n|------|------|------|----------|\\n| **profile** | `user/memories/profile.md` | 用户基本信息 | ✅ 合并到单文件 |\\n| **preferences** | `user/memories/preferences/` | 按主题的用户偏好 | ✅ 可追加 |\\n| **entities** | `user/memories/entities/` | 实体记忆（人物、项目） | ✅ 可追加 |\\n| **events** | `user/memories/events/` | 事件记录（决策、里程碑） | ❌ 不更新 |\\n| **cases** | `agent/memories/cases/` | 学习的案例 | ❌ 不更新 |\\n| **patterns** | `agent/memories/patterns/` | 学习的模式 | ✅ 可合并 |\\n| **tools** | `agent/memories/tools/` | 工具使用经验与最佳实践 | ✅ 可合并 |\\n| **skills** | `agent/memories/skills/` | 技能执行经验与工作流策略 | ✅ 可合并 |\\n\\n### 使用\\n\\n```python\\n# 记忆从会话中自动提取\\nsession = client.session()\\nawait session.add_message(\\"user\\", [{\\"type\\": \\"text\\", \\"text\\": \\"我喜欢深色模式\\"}])\\ncommit = await session.commit()  # 启动后台记忆提取\\ntask = await client.get_task(commit[\\"task_id\\"])  # 轮询直到 task[\\"status\\"] == \\"completed\\"\\n\\n# 搜索记忆\\nresults = await client.find(\\n    \\"用户界面偏好\\",\\n    target_uri=\\"viking://user/memories/\\"\\n)\\n```\\n\\n## Skill（技能）\\n\\n技能是 Agent 可以调用的能力，比如目前的Skills、MCP等均属于此类。\\n\\n### 特点\\n\\n- **定义的能力：**用于完成某项工作的工具定义\\n- **相对静态：**运行时技能定义不变，但和工具相关的使用记忆会在记忆中更新\\n- **可调用：**Agent 决定何时使用哪种技能\\n\\n### 存储位置\\n\\n```\\nviking://agent/skills/{skill-name}/\\n├── .abstract.md          # L0: 简短描述\\n├── SKILL.md   \\t\\t\\t\\t\\t\\t# L1: 详细概览\\n└── scripts           \\t\\t# L2: 完整定义\\n\\n```\\n\\n### 使用\\n\\n```python\\n# 添加技能\\nawait client.add_skill({\\n    \\"name\\": \\"search-web\\",\\n    \\"description\\": \\"搜索网络获取信息\\",\\n    \\"content\\": \\"# search-web\\\\n...\\"\\n})\\n\\n# 搜索技能\\nresults = await client.find(\\n    \\"网络搜索\\",\\n    target_uri=\\"viking://agent/skills/\\"\\n)\\n```\\n\\n## 统一检索\\n\\n根据Agent的需求需求，支持对三种上下文类型统一搜索，提供全面信息：\\n\\n```python\\n# 跨所有上下文类型搜索\\nresults = await client.find(\\"用户认证\\")\\n\\nfor ctx in results.memories:\\n    print(f\\"记忆: {ctx.uri}\\")\\nfor ctx in results.resources:\\n    print(f\\"资源: {ctx.uri}\\")\\nfor ctx in results.skills:\\n    print(f\\"技能: {ctx.uri}\\")\\n```\\n\\n## 相关文档\\n\\n- [架构概述](./01-architecture.md) - 系统整体架构\\n- [上下文层级](./03-context-layers.md) - L0/L1/L2 模型\\n- [Viking URI](./04-viking-uri.md) - URI 规范\\n- [会话管理](./08-session.md) - 记忆提取机制\\n"},"headers":[],"relativePath":"zh/concepts/02-context-types.md","filePath":"zh/concepts/02-context-types.md","lastUpdated":1775135341000}'),e={name:"zh/concepts/02-context-types.md"};function l(h,s,p,k,r,d){return a(),t("div",null,[...s[0]||(s[0]=[n("",33)])])}const E=i(e,[["render",l]]);export{g as __pageData,E as default};
